package pe.org.camaracomercioica.protestos.repository;
import org.junit.jupiter.api.Test; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest; import org.springframework.data.domain.PageRequest; import pe.org.camaracomercioica.protestos.model.*; import java.time.Instant; import static org.assertj.core.api.Assertions.assertThat;
@DataJpaTest class FilteringRepositoryTest { @Autowired SolicitudRepository solicitudes;@Autowired AuditoriaRepository auditorias;@Autowired RolRepository roles;@Autowired UsuarioRepository users;@Autowired EntidadFinancieraRepository entidades;
 @Test void filtraSolicitudesPorEstadoYEntidad(){var rol=new Rol();rol.setNombre("ADMIN_X");rol=roles.save(rol);var u=new Usuario();u.setNombreCompleto("Test");u.setEmail("filter@test.local");u.setPasswordHash("hash");u.setRol(rol);u=users.save(u);var e1=new EntidadFinanciera();e1.setRuc("20999999991");e1.setRazonSocial("Uno");e1=entidades.save(e1);var e2=new EntidadFinanciera();e2.setRuc("20999999992");e2.setRazonSocial("Dos");e2=entidades.save(e2);solicitudes.save(sol("A",u,e1,EstadoSolicitud.REGISTRADA,"12345678"));solicitudes.save(sol("B",u,e2,EstadoSolicitud.APROBADA_ENTIDAD,"12345679"));assertThat(solicitudes.filtrar(EstadoSolicitud.APROBADA_ENTIDAD,e2.getId(),PageRequest.of(0,10))).extracting(Solicitud::getCodigo).containsExactly("B");assertThat(solicitudes.filtrar(null,null,PageRequest.of(0,10))).hasSize(2);}
 @Test void filtraAuditoriaConParametrosOpcionalesYRango(){var a=new Auditoria();a.setActor("admin@test.local");a.setAccion("CREAR");a.setRecurso("SOLICITUD");a.setFecha(Instant.parse("2026-01-10T10:00:00Z"));auditorias.save(a);var result=auditorias.filtrar("admin","CREAR","SOLICITUD",Instant.parse("2026-01-01T00:00:00Z"),Instant.parse("2026-02-01T00:00:00Z"),PageRequest.of(0,10));assertThat(result).hasSize(1);assertThat(auditorias.filtrar("otro",null,null,null,null,PageRequest.of(0,10))).isEmpty();}
 private Solicitud sol(String code,Usuario u,EntidadFinanciera e,EstadoSolicitud estado,String documento){var s=new Solicitud();s.setCodigo(code);s.setSolicitante(u);s.setEntidad(e);s.setEstado(estado);s.setMotivo("motivo");s.setNumeroDocumentoDeudor(documento);s.setMonto(new java.math.BigDecimal("10.00"));return s;}}
